package com.knoxhack.echostationfall.progression;
import java.util.Locale; import net.minecraft.core.BlockPos;
public enum StationSection { DOCKING_RING("docking_ring","Docking Ring",0,1), CREW_QUARTERS("crew_quarters","Crew Quarters",40,2), HYDROPONICS_BAY("hydroponics_bay","Hydroponics Bay",80,3), MEDICAL_WING("medical_wing","Medical Wing",120,4), ENGINEERING_DECK("engineering_deck","Engineering Deck",160,3), DATA_CORE("data_core","Data Core",200,4), OBSERVATION_DECK("observation_deck","Observation Deck",240,2), CONTAINMENT_WING("containment_wing","Containment Wing",280,5), COMMAND_MODULE("command_module","Command Module",320,6);
    private final String key,displayName; private final int centerX,hazardIntensity; StationSection(String k,String d,int x,int h){key=k;displayName=d;centerX=x;hazardIntensity=h;} public String key(){return key;} public String displayName(){return displayName;} public int centerX(){return centerX;} public int hazardIntensity(){return hazardIntensity;} public BlockPos center(){return new BlockPos(centerX,96,0);} public BlockPos powerNodePos(){return new BlockPos(centerX,96,-7);} public BlockPos logTerminalPos(){return new BlockPos(centerX-5,96,6);} public BlockPos doorPos(){return new BlockPos(centerX+18,96,0);} public StationSection next(){int i=ordinal()+1; return i>=values().length?null:values()[i];}
    public static StationSection byKey(String k){String n=k==null?"":k.trim().toLowerCase(Locale.ROOT); for(StationSection s:values()) if(s.key.equals(n)||s.name().toLowerCase(Locale.ROOT).equals(n)) return s; return DOCKING_RING;} public static StationSection fromPosition(BlockPos p){StationSection best=DOCKING_RING; int d=Integer.MAX_VALUE; for(StationSection s:values()){int x=Math.abs(p.getX()-s.centerX); if(x<d){d=x;best=s;}} return best;}
}
